// Classifica o tipo de erro
const error = $json.body || $json;
const errorType = (() => {
  const msg = (error.message || error.error || '').toLowerCase();
  if (msg.includes('timeout')) return 'timeout';
  if (msg.includes('401') || msg.includes('unauthorized')) return 'auth';
  if (msg.includes('404')) return 'not_found';
  if (msg.includes('429') || msg.includes('rate limit')) return 'rate_limit';
  if (msg.includes('500') || msg.includes('internal')) return 'server_error';
  return 'unknown';
})();

const shouldRetry = ['timeout', 'rate_limit', 'server_error'].includes(errorType);
const retryCount = (error.retryCount || 0) + 1;
const maxRetries = 3;

return {
  errorType,
  shouldRetry: shouldRetry && retryCount <= maxRetries,
  retryCount,
  maxRetries,
  error: error,
  timestamp: new Date().toISOString()
};
